{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[{"file_id":"1Yd_0lCh1FxbER2OX_6PUHptttmk6i-qb","timestamp":1775120758370}],"gpuType":"T4","authorship_tag":"ABX9TyOi0X+NvYM3ELdEWDQTUCDe"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"},"accelerator":"GPU"},"cells":[{"cell_type":"code","source":["!pip install -q osmnx geopandas pyproj rasterio matplotlib segmentation-models-pytorch\n","from google.colab import drive\n","drive.mount('/content/drive')\n","import rasterio\n","import numpy as np\n","import osmnx as ox\n","from rasterio.features import rasterize\n","from pyproj import Transformer\n","import geopandas as gpd\n","\n","IMG_PATH = \"/content/drive/MyDrive/Sentinel_AI_Project.tif\"\n","\n","img = rasterio.open(IMG_PATH)\n","bounds = img.bounds\n","crs = img.crs\n","transform = img.transform\n","H, W = img.height, img.width\n","\n","# Read bands\n","blue  = img.read(1).astype(np.float32)\n","green = img.read(2).astype(np.float32)\n","red   = img.read(3).astype(np.float32)\n","nir   = img.read(4).astype(np.float32)\n","\n","# Indices\n","eps = 1e-6\n","ndvi = (nir - red) / (nir + red + eps)\n","ndwi = (green - nir) / (green + nir + eps)\n","\n","veg = ndvi > 0.25\n","water = ndwi > 0.1\n","\n","# OSM fetch\n","transformer = Transformer.from_crs(crs, \"EPSG:4326\", always_xy=True)\n","west, south = transformer.transform(bounds.left, bounds.bottom)\n","east, north = transformer.transform(bounds.right, bounds.top)\n","\n","cx, cy = (east+west)/2, (north+south)/2\n","\n","buildings = ox.features_from_point((cy, cx), tags={'building': True}, dist=3000)\n","roads = ox.graph_to_gdfs(ox.graph_from_point((cy, cx), dist=3000), nodes=False)\n","\n","# Reproject\n","buildings = buildings.to_crs(crs)\n","roads = roads.to_crs(crs)\n","\n","# Rasterize\n","def rasterize_gdf(gdf):\n","    shapes = [(g, 1) for g in gdf.geometry if g is not None]\n","    return rasterize(shapes, out_shape=(H, W), transform=transform)\n","\n","road_mask = rasterize_gdf(roads)\n","building_mask = rasterize_gdf(buildings)\n","\n","# Final mask\n","mask = np.zeros((H, W), dtype=np.uint8)\n","mask[veg] = 1\n","mask[water] = 2\n","mask[building_mask == 1] = 3\n","mask[road_mask == 1] = 0\n","\n","# Save\n","with rasterio.open(\"/content/drive/MyDrive/training_mask_osm.tif\", \"w\",\n","    driver=\"GTiff\",\n","    height=H,\n","    width=W,\n","    count=1,\n","    dtype=mask.dtype,\n","    crs=crs,\n","    transform=transform) as dst:\n","\n","    dst.write(mask, 1)\n","\n","print(\"✅ Mask created\")"],"metadata":{"colab":{"base_uri":"https://localhost:8080/"},"id":"2oRqSgliRKAZ","executionInfo":{"status":"ok","timestamp":1776080360591,"user_tz":720,"elapsed":259739,"user":{"displayName":"Srushti Telang","userId":"02687955996843246920"}},"outputId":"8742f890-b34b-4cc4-f46e-7b48de7e397c"},"execution_count":2,"outputs":[{"output_type":"stream","name":"stdout","text":["Drive already mounted at /content/drive; to attempt to forcibly remount, call drive.mount(\"/content/drive\", force_remount=True).\n","✅ Mask created\n"]}]}]}